import faiss
import numpy as np

def retrieve_faiss(query, index, docstore):
    query_embedding = embedder.encode([query])
    scores, indices = index.search(query_embedding, k=5)
    sources = [docstore[i] for i in indices[0]]
    return {
        'query': query,
        'sources': sources,
        'scores': scores[0].tolist(),
        'metadata': {'retriever': 'FAISS'}
    }

class FAISSRetrieverAgent(AssistantAgent):
    def retrieve(self, query):
        return retrieve_faiss(query, self.index, self.docstore)

def synthesize_with_citations(retrievals):
    sources = []
    for r in retrievals:
        sources.extend(r['sources'])

    prompt = f"""Synthesize answer from these sources only:
{sources}
Cite sources using [1], [2] format. Return JSON with 'answer' and 'citations'"""

    response = llm_client.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": prompt}]
    )
    return response.choices[0].message.content

