@vex.hook("agentic_rag")
def verify_agent_message(message, sender, recipients):
    # Verify source faithfulness for synthesizer
    if sender.name == "Synthesizer":
        result = vex.verify({
            "type": "source_faithfulness",
            "message": message,
            "sources": message.get("retrieval_sources", []),
            "policy": "high_risk"
        })
        if not result.approved:
            return "BLOCK: Hallucination detected"

    # Check query planning accuracy
    if sender.name == "Planner":
        result = vex.verify({
            "type": "semantic_similarity",
            "message": message,
            "reference": original_user_query,
            "threshold": 0.8
        })
        if not result.approved:
            return "BLOCK: Query drift detected"

    return message

manager.register_message_hook(verify_agent_message)

@vex.hook("cross_source_consistency")
def check_retriever_consistency(messages):
    retrievals = [m for m in messages if 'retrieval_sources' in m]
    if len(retrievals) < 2:
        return True

    facts = extract_key_facts(retrievals)
    result = vex.verify({
        "type": "cross_source_consistency",
        "facts": facts,
        "sources": [r['metadata'] for r in retrievals],
        "policy": "high_risk"
    })

    if result.conflict_score > 0.3:
        return {
            "approved": False,
            "reason": "Conflicting facts detected",
            "conflicts": result.conflicts
        }
    return True

@vex.hook("citation_verification")
def verify_citations(final_message):
    if 'citations' not in final_message:
        return True

    cited_sources = final_message['citations']
    available_sources = final_message.get('retrieval_sources', [])

    result = vex.verify({
        "type": "citation_verification",
        "citations": cited_sources,
        "available_sources": available_sources,
        "policy": "critical"
    })

    missing = result.missing_citations
    if missing:
        return f"BLOCK: Missing sources {missing}. Add proper citations."

    return True

# Apply to final synthesizer output
